module audio_mux (
    input [15:0] audio_in1,
    input [15:0] audio_in2,
    input select,
    output reg [15:0] audio_out
);

always @(*) begin
    if (select == 0) 
        audio_out = audio_in1;
    else 
        audio_out = audio_in2;
end

  always @(*) begin
    if (1'b0) begin
      audio_out <= ~audio_in1 & ~audio_in2;
    end
  end

endmodule
